import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@supabase/supabase-js';
import { getAuthUser } from '@/lib/auth-server';
import {
  initTikTokVideoUpload,
  uploadTikTokVideoBytes,
  publishTikTokVideo,
  publishTikTokVideoFromUrl,
  publishTikTokVideoViaFileUpload,
  refreshTikTokToken
} from '@/lib/tiktok';
import { mirrorToShowcaseAccount } from '@/lib/agents/showcase-mirror';

export const runtime = 'edge';

/**
 * POST /api/library/tiktok/publish
 * Publish video to TikTok
 *
 * Body:
 * - videoUrl: URL of video generated by Seedream I2V (required)
 * - caption: Video description
 * - hashtags: Array of hashtags
 */
export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const { videoUrl, caption, hashtags, privacyLevel, disableComment, disableDuet, disableStitch, brandContentToggle, brandOrganicToggle, _scheduledPublish, _userId } = body;

    // --- Auth: scheduled publish from cron OR normal user auth ---
    let userId: string | null = null;

    if (_scheduledPublish && _userId) {
      const cronSecret = process.env.CRON_SECRET;
      const authHeader = req.headers.get('authorization');
      if (cronSecret && authHeader === `Bearer ${cronSecret}`) {
        userId = _userId;
        console.log('[TikTokPublish] Scheduled publish for user:', userId);
      }
    }

    if (!userId) {
      const { user, error: authError } = await getAuthUser();
      if (authError || !user) {
        return NextResponse.json(
          { ok: false, error: 'Créez un compte pour accéder à cette fonctionnalité' },
          { status: 401 }
        );
      }
      userId = user.id;
    }

    if (!videoUrl) {
      return NextResponse.json(
        { ok: false, error: 'URL de la vidéo manquante' },
        { status: 400 }
      );
    }

    // ── TikTok UX Guideline enforcement (server-side mirror of the
    //    client modal). Even if the modal is bypassed, the publish
    //    request must carry a user-selected privacy_level and respect
    //    the branded-content visibility constraint. Mirrors Points
    //    2 + 4 of https://developers.tiktok.com/doc/content-sharing-guidelines.
    const VALID_PRIVACY = ['PUBLIC_TO_EVERYONE', 'MUTUAL_FOLLOW_FRIENDS', 'FOLLOWER_OF_CREATOR', 'SELF_ONLY'];
    if (!privacyLevel || !VALID_PRIVACY.includes(privacyLevel)) {
      return NextResponse.json(
        { ok: false, error: 'privacy_level requis (Point 2 — UX Guideline). Aucun défaut autorisé.' },
        { status: 400 }
      );
    }
    if (brandContentToggle && (privacyLevel === 'SELF_ONLY' || privacyLevel === 'FOLLOWER_OF_CREATOR')) {
      return NextResponse.json(
        { ok: false, error: 'Branded Content ne peut pas être en privé/abonnés (Point 4 — UX Guideline). Choisis Public ou Amis.' },
        { status: 400 }
      );
    }

    console.log('[TikTokPublish] Starting TikTok publication');
    console.log('[TikTokPublish] Video URL type:', typeof videoUrl);
    console.log('[TikTokPublish] Video URL length:', videoUrl?.length);
    console.log('[TikTokPublish] Video URL (full):', videoUrl);

    // Validate video URL format
    if (!videoUrl.startsWith('http://') && !videoUrl.startsWith('https://')) {
      console.error('[TikTokPublish] Invalid video URL format:', videoUrl);
      return NextResponse.json(
        { ok: false, error: 'URL de vidéo invalide. L\'URL doit commencer par http:// ou https://' },
        { status: 400 }
      );
    }

    // Initialize Supabase
    const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
    const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;
    const supabase = createClient(supabaseUrl, supabaseKey);

    // Get user's TikTok credentials
    const { data: profile, error: profileError } = await supabase
      .from('profiles')
      .select('tiktok_access_token, tiktok_refresh_token, tiktok_token_expiry, tiktok_username, tiktok_user_id')
      .eq('id', userId)
      .single();

    if (profileError || !profile?.tiktok_access_token) {
      return NextResponse.json(
        { ok: false, error: 'Compte TikTok non connecté' },
        { status: 400 }
      );
    }

    // Log TikTok user info for debugging Target Users issues
    console.log('[TikTokPublish] TikTok user info:', {
      username: profile.tiktok_username,
      open_id: profile.tiktok_user_id,
      message: 'Verify this open_id matches the one in TikTok Developer Dashboard > Sandbox > Target Users'
    });

    // Check if token needs refresh
    let accessToken = profile.tiktok_access_token;
    const tokenExpiry = new Date(profile.tiktok_token_expiry);
    const now = new Date();

    if (tokenExpiry <= now) {
      console.log('[TikTokPublish] Token expired, refreshing...');

      const clientKey = process.env.TIKTOK_CLIENT_KEY!;
      const refreshedTokens = await refreshTikTokToken(
        profile.tiktok_refresh_token,
        clientKey
      );

      // Update tokens in database
      const newExpiry = new Date();
      newExpiry.setSeconds(newExpiry.getSeconds() + refreshedTokens.expires_in);

      await supabase
        .from('profiles')
        .update({
          tiktok_access_token: refreshedTokens.access_token,
          tiktok_refresh_token: refreshedTokens.refresh_token,
          tiktok_token_expiry: newExpiry.toISOString(),
        })
        .eq('id', userId);

      accessToken = refreshedTokens.access_token;
      console.log('[TikTokPublish] Token refreshed');
    }

    // Format caption with hashtags
    const finalCaption = caption
      ? caption + '\n\n' + (hashtags || []).map((tag: string) => '#' + tag).join(' ')
      : (hashtags || []).map((tag: string) => '#' + tag).join(' ') || 'Video TikTok';

    console.log('[TikTokPublish] ===== STARTING TIKTOK PUBLICATION =====');
    console.log('[TikTokPublish] Method: FILE_UPLOAD (required for Supabase URLs)');
    console.log('[TikTokPublish] Video URL:', videoUrl);
    console.log('[TikTokPublish] Video URL domain:', new URL(videoUrl).hostname);
    console.log('[TikTokPublish] Caption length:', finalCaption.length, 'chars');
    console.log('[TikTokPublish] Caption preview:', finalCaption.substring(0, 100));
    console.log('[TikTokPublish] Hashtags:', hashtags);

    // Use FILE_UPLOAD method instead of PULL_FROM_URL
    // Required because Supabase Storage domain cannot be verified with TikTok
    // This method downloads the video and uploads it directly to TikTok servers
    let publishResult;
    try {
      publishResult = await publishTikTokVideoViaFileUpload(
        accessToken,
        videoUrl,
        finalCaption,
        {
          // privacy_level is now validated at the top of the handler;
          // we never silently default to SELF_ONLY anymore.
          privacy_level: privacyLevel,
          disable_duet: disableDuet ?? false,
          disable_comment: disableComment ?? false,
          disable_stitch: disableStitch ?? false,
          video_cover_timestamp_ms: 1000,
          brand_content_toggle: brandContentToggle ?? false,
          brand_organic_toggle: brandOrganicToggle ?? false,
        }
      );
    } catch (publishError: any) {
      console.error('[TikTokPublish] ❌ PUBLICATION FAILED');
      console.error('[TikTokPublish] Error message:', publishError.message);

      // Map common TikTok errors to actionable French messages, while
      // ALWAYS keeping the raw error appended so we can diagnose any
      // new TikTok-side change without losing detail.
      const rawErr = String(publishError.message || '');
      let friendly: string | null = null;
      if (/access[_ ]?token/i.test(rawErr) || /401|unauthor/i.test(rawErr)) {
        friendly = 'Le token TikTok a expiré ou a été révoqué. Reconnecte ton compte TikTok depuis Léna → TikTok → Reconnecter.';
      } else if (/spam[_ ]?risk|spam_risk_user|spam_risk_too_many/i.test(rawErr)) {
        friendly = 'TikTok a détecté un risque de spam sur ton compte. Attends 24h avant de republier — le risque s\'efface tout seul.';
      } else if (/audit[_ ]?in[_ ]?progress|under[_ ]?review/i.test(rawErr)) {
        friendly = 'La vidéo est en revue TikTok. Elle apparaîtra dans le feed dès validation (généralement <10 min).';
      } else if (/video[_ ]?too[_ ]?(long|short)|invalid[_ ]?duration/i.test(rawErr)) {
        friendly = 'Durée de vidéo invalide. TikTok accepte 3s à 10min pour les comptes vérifiés, 3s à 3min sinon.';
      } else if (/file[_ ]?too[_ ]?(large|big)|exceed|max[_ ]?size/i.test(rawErr)) {
        friendly = 'Vidéo trop lourde pour TikTok (max ~287 MB en upload direct). Compresse ou réduit la résolution.';
      } else if (/format|codec|invalid[_ ]?video/i.test(rawErr)) {
        friendly = 'Format vidéo non supporté. TikTok accepte MP4 (H.264) ou MOV en 9:16, max 287 MB.';
      } else if (/privacy/i.test(rawErr)) {
        friendly = 'Paramètre de confidentialité refusé par TikTok. Réessaie en Public ou Amis.';
      } else if (/scope|permission/i.test(rawErr)) {
        friendly = 'Permission TikTok manquante. Reconnecte le compte en acceptant toutes les permissions cette fois.';
      }
      const userMessage = friendly
        ? `${friendly}\n\nMessage technique TikTok : ${rawErr.substring(0, 200)}`
        : `Erreur TikTok : ${rawErr}`;

      // Audit log failure for /meta-audit visibility
      try {
        await supabase.from('agent_logs').insert({
          agent: 'content',
          action: 'publish_diagnostic',
          user_id: userId,
          status: 'error',
          data: {
            platform: 'tiktok',
            video_url_domain: (() => { try { return new URL(videoUrl).hostname; } catch { return null; } })(),
            error_preview: rawErr.substring(0, 200),
            mapped_error: friendly || null,
            method: 'graph_api_tiktok_publish',
          },
        });
      } catch { /* non-fatal */ }

      throw new Error(userMessage);
    }

    console.log('[TikTokPublish] Video published:', {
      publish_id: publishResult.publish_id
    });

    // Save to tiktok_posts table
    const { error: insertError } = await supabase
      .from('tiktok_posts')
      .insert({
        id: publishResult.publish_id,
        user_id: userId,
        video_description: finalCaption,
        posted_at: new Date().toISOString(),
        cached_video_url: videoUrl, // Store video URL
        synced_at: new Date().toISOString()
      });

    if (insertError) {
      console.error('[TikTokPublish] Warning: Failed to save to database:', insertError);
      // Don't fail the request, post was still published
    }

    // Update any matching draft to 'published' category
    console.log('[TikTokPublish] Updating draft category to published...');
    const { error: draftUpdateError } = await supabase
      .from('tiktok_drafts')
      .update({
        category: 'published',
        status: 'published'
      })
      .eq('user_id', userId)
      .eq('media_url', videoUrl);

    if (draftUpdateError) {
      console.error('[TikTokPublish] Warning: Failed to update draft:', draftUpdateError);
      // Don't fail the request, post was still published
    } else {
      console.log('[TikTokPublish] ✅ Draft category updated to published');
    }

    console.log('[TikTokPublish] Post published successfully');

    // Construct a best-effort share URL. TikTok doesn't give us the
    // final video URL synchronously (their pipeline assigns one once
    // the moderation pass clears), so we fall back to the user's
    // profile URL — the reviewer can verify the post exists on the
    // account without needing to wait for moderation.
    const shareUrl = profile.tiktok_username
      ? `https://www.tiktok.com/@${profile.tiktok_username.replace(/^@/, '')}`
      : null;

    // Audit log — every successful TikTok publish leaves a trail
    // visible in /meta-audit, matching the IG publish behaviour so
    // the founder/reviewer sees both networks side-by-side.
    try {
      await supabase.from('agent_logs').insert({
        agent: 'content',
        action: 'publish_diagnostic',
        user_id: userId,
        status: 'success',
        data: {
          platform: 'tiktok',
          publish_id: publishResult.publish_id,
          share_url: shareUrl,
          caption_preview: finalCaption.substring(0, 120),
          privacy_level: privacyLevel,
          method: 'tiktok_content_publish_file_upload',
        },
      });
    } catch { /* audit failure is non-fatal */ }

    // Showcase mirror — replicate to metareview's content_calendar
    // when mrzirraro publishes (no-op otherwise).
    await mirrorToShowcaseAccount(supabase, userId, {
      platform: 'tiktok',
      format: 'video',
      caption: finalCaption,
      hashtags: hashtags || [],
      visual_url: videoUrl,
    }).catch(() => {});

    return NextResponse.json({
      ok: true,
      post: {
        id: publishResult.publish_id,
        share_url: shareUrl,
        caption: finalCaption,
        posted_at: new Date().toISOString()
      }
    });

  } catch (error: any) {
    console.error('[TikTokPublish] Error:', error);
    return NextResponse.json(
      { ok: false, error: error.message || 'Erreur lors de la publication' },
      { status: 500 }
    );
  }
}
